children:
    	import QtQuick
    	import Quickshell.Services.UPower
    	import Quickshell
    	import qs.ui.controls.primitives
    	import QtQuick.Layouts
    	import qs.ui.controls.providers
    	import qs.ui.controls.auxiliary.widget
    	import qs.config
    	import qs
    	WidgetItem {
	        id: root

       property var devices: [
           { type: UPower.displayDevice.isLaptopBattery ? "laptop" : "desktop", name: "Micky's Macbook Air 2019", level: UPower.displayDevice.percentage },
           { type: "", name: "", level: 0 },
           { type: "", name: "", level: 0 },
           { type: "", name: "", level: 0 }
       ]

       RowLayout {
           id: batteryRow
           anchors.centerIn: parent
           spacing: 20

           Repeater {
               model: root.devices

               ColumnLayout {
                   spacing: 6
                   Layout.alignment: Qt.AlignHCenter


                   CFCircularProgress {
                       Layout.alignment: Qt.AlignVCenter
                       id: battery
                       implicitSize: 80*bw.sF
                       lineWidth: 4
                       colPrimary: Config.appearance.multiAccentColor ? "#3cc969" : AccentColor.color
                       colSecondary: Config.general.darkMode ? "#444" : "#ddd"
                       gapAngle: 0
                       value: modelData.level

                       Loader {
                           id: batteryIcon
                           active: modelData.name != ""
                           anchors.centerIn: parent
                           CFVI {
                               id: bIcon
                               source: modelData.name == "" ? "" :  Qt.resolvedUrl(Quickshell.shellDir + "/media/icons/devices/" + modelData.type + ".svg")
                               size: bw.textSizeXL
                               anchors.centerIn: parent
                               color: Config.appearance.multiAccentColor ? (Config.general.darkMode ? '#fff' : "#222") : AccentColor.color
                           }
                       }
                   }


                   CFText {
                       text: Math.round(modelData.level * 100) + "%"
                       opacity: (modelData.name == "") ? 0 : 1
                       color: Config.general.darkMode ? "#fff" : "#222"
                       font.pixelSize: bw.textSizeM
                       horizontalAlignment: Text.AlignHCenter
                       Layout.alignment: Qt.AlignHCenter
                   }
               }
           }
       }
	    }

    	import QtQuick
    	import Quickshell.Services.UPower
    	import Quickshell
    	import qs.ui.controls.primitives
    	import QtQuick.Layouts
    	import qs.ui.controls.providers
    	import qs.ui.controls.auxiliary.widget
    	import qs.config
    	import qs
    	WidgetItem {
	        id: root

       Rectangle {
           id: background
           color: "transparent"
           anchors.fill: parent
           anchors.margins: 15
           transform: [
               Scale { origin.x: background.width/2; xScale: 1.5; yScale: 1.5 },
               Translate { y: -6 }
           ]

           Text {
               id: text
               anchors.fill: parent
               color: Config.general.darkMode ? "#fff" : "#222"
               font.family: Fonts.sFProRounded.family
               font.pixelSize: 25
               transform: [
                   Translate { y: -15 }
               ]
               font.weight: Font.Bold
               text: Time.getTime("hh:mm")
               horizontalAlignment: Text.AlignHCenter
               verticalAlignment: Text.AlignVCenter
           }

           PathView {
               id: pathView
               model: 60
               anchors.fill: parent

               delegate: Rectangle {
                   id: rect
                   required property int modelData
                   width: pathView.width / 60
                   height: pathView.width / 20
                   color: "white"
                   radius: 15
                   antialiasing: true
                   rotation: modelData * 360 / pathView.model


                   property int diff: (Time.getSeconds() - modelData + pathView.model) % pathView.model


                   property int tailLength: 59
                   opacity: diff <= tailLength ? Math.exp(-0.08 * diff) : 0

                   Behavior on opacity {
                       NumberAnimation { duration: 200; easing.type: Easing.InOutQuad }
                   }
               }

               path: Path {
                   id: myPath
                   property real radius: pathView.width / 10
                   startX: pathView.width / 2

                   PathLine {
                       relativeX: pathView.width / 4
                   }

                   PathArc {
                       relativeX: myPath.radius
                       relativeY: myPath.radius
                       radiusX: myPath.radius
                       radiusY: myPath.radius
                   }

                   PathLine {
                       relativeX: 0
                       relativeY: pathView.width / 2
                   }

                   PathArc {
                       relativeX: -myPath.radius
                       relativeY: myPath.radius
                       radiusX: myPath.radius
                       radiusY: myPath.radius
                   }

                   PathLine {
                       relativeX: -pathView.width / 2
                       relativeY: 0
                   }

                   PathArc {
                       relativeX: -myPath.radius
                       relativeY: -myPath.radius
                       radiusX: myPath.radius
                       radiusY: myPath.radius
                   }

                   PathLine {
                       relativeX: 0
                       relativeY: -pathView.width / 2
                   }

                   PathArc {
                       relativeX: myPath.radius
                       relativeY: -myPath.radius
                       radiusX: myPath.radius
                       radiusY: myPath.radius
                   }

                   PathLine {
                       relativeX: pathView.width / 4
                       relativeY: 0
                   }
               }
           }
       }
	    }

  	import QtQuick
  	import QtQuick.VectorImage
  	import Quickshell.Widgets
  	import Quickshell
  	import Quickshell.Io
		import QtQuick.Shapes
  	import qs.ui.controls.primitives
  	import QtQuick.Layouts
		import QtQuick.Controls
  	import qs.ui.controls.providers
  	import qs.ui.controls.auxiliary.widget
  	import qs.config
  	import qs
  	WidgetItem {
	        id: wi
	        ClippingRectangle {
				anchors.fill: parent
				anchors.margins: 2
				color: "#222"
				radius: 25
				CFRectExperimental {
					id: bg
					anchors.fill: parent
					scale: 2
					rotation: -20
					gradient: LinearGradient {
						y2: bw.height
						GradientStop { position: 0.0; color: Config.general.darkMode ? "#08427d" : "#08427d" }
						GradientStop { position: 1.0; color: Config.general.darkMode ? "#5487c0" : "#5487c0" }
					}
				}
			}
			Item {
				id: root
				anchors.fill: parent
				Timer {
					id: notifTimer
					interval: 10000 
					running: true
					repeat: true
					onTriggered: {
						weatherProc.running = true
					}
				}

				Process {
					id: weatherProc
					command: ["sh", "-c", `curl -s wttr.in/${Config.widgets.location}?format=j1 | jq '{location: .nearest_area[0].areaName[0].value, temperature: .current_condition[0].temp_${Config.widgets.tempUnit}, feelsLikeTemp: .current_condition[0].FeelsLike${Config.widgets.tempUnit}, description: .current_condition[0].weatherDesc[0].value, highTemp: .weather[0].maxtemp${Config.widgets.tempUnit}, lowTemp: .weather[0].mintemp${Config.widgets.tempUnit}}'`]
					running: true
					stdout: StdioCollector {
						onStreamFinished: {
							const text = this.text;
							const json = JSON.parse(text);
							root.location = Config.widgets.useLocationInUI ? Config.widgets.location : json.location;
							root.temperature = json.temperature;
							root.description = json.description;
							root.hlVal = "H: " + json.highTemp + "°" + Config.widgets.tempUnit + ", L: " + json.lowTemp + "°" + Config.widgets.tempUnit;
						}
					}
					stderr: StdioCollector {
						onStreamFinished: if (text != "") Logger.e("Desktop::Widget::BWD2x2", "weather fetch error:", text);
					}
				}

				property string location: "--"
				property int temperature: 0
				property string description: ""
				property string hlVal: "H: --, L: --"
				property url icon: Qt.resolvedUrl(Quickshell.shellDir + "/media/icons/weather/cloud-sun.svg")

				CFText {
					id: locationT
					text: root.location
					color: "#fff"
					font.pixelSize: bw.textSizeM
					topPadding: 15
					leftPadding: 15
					verticalAlignment: Text.AlignTop
					horizontalAlignment: Text.AlignLeft
				}

				CFText {
					text: root.temperature + "°" + Config.widgets.tempUnit
					color: "#fff"
					font.pixelSize: bw.textSizeXXL
					font.weight: 300
					leftPadding: 15
					anchors.top: locationT.bottom
					horizontalAlignment: Text.AlignLeft
				}

				VectorImage {
					id: icon
					source: root.icon
					width: 20
					height: 20
					preferredRendererType: VectorImage.CurveRenderer
					anchors.bottom: descriptionT.top
					anchors.left: parent.left
					anchors.leftMargin: 15
					anchors.bottomMargin: 3
				}


				Text {
					id: hlT
					text: root.hlVal
					color: "#fff"
					font.pixelSize: bw.textSize
					leftPadding: 15
					bottomPadding: 15
					horizontalAlignment: Text.AlignLeft
					anchors.bottom: parent.bottom
				}

				Text {
					id: descriptionT
					text: root.description
					color: "#fff"
					font.pixelSize: bw.textSize
					leftPadding: 15
					anchors.bottom: hlT.top
				}
			}
	    }
